#include<bits/stdc++.h>
#define LL long long
using namespace std;
const int N = 505;
struct line{int to,val;};//用来存边的结构体
struct node{int u,d;};//用来跑 Dijkstra 的结构体
int n,x[N],y[N],n2,dis[N],ans;bool flag[N];//各种数组定义
int dx[]={1,0,-1,0},dy[]={0,1,0,-1};//方向数组，便于计算虚点
map<pair<int,int>,int> mp;vector<line> g[N];//用于标记点的 map 以及用于存边的 vector
bool operator < (const node &A,const node &B){return A.d>B.d;}//结构体重载运算符
priority_queue<node> q;//用来跑 Dijkstra 的优先队列，结构体类型，重载运算符在上面
bool Is_At_Line(int id,int X1,int Y1,int X2,int Y2){
    if(X1==X2&&x[id]==X1){//x 坐标值相同的线
        if(Y1>Y2)swap(Y1,Y2);//大小关系确定方便判断
        if(Y1<=y[id]&&y[id]<=Y2)return 1;//如果在范围内那么返回 1
    }
    if(Y1==Y2&&y[id]==Y1){//y 坐标值相同的线
        if(X1>X2)swap(X1,X2);//大小关系确定方便判断
        if(X1<=x[id]&&x[id]<=X2)return 1;//如果在范围内那么返回 1
    }
    return 0;//都不成那么失败，返回 0
}
bool Can_Farm(int X1,int Y1,int X2,int Y2){
    for(int i=1;i<=n;i++)
        if(Is_At_Line(i,X1,Y1,X2,Y2))return 0;
    //枚举每个牧场，依次处理
    return 1;
}
bool Can_Merge(int p1,int p2){
    bool flag=0;
    if(p1==5&&p2==8)flag=1;
    if(x[p1]==x[p2]||y[p1]==y[p2])
        return Can_Farm(x[p1],y[p1],x[p2],y[p2]);
    //如果原来就是一条线那么直接判断
    if(Can_Farm(x[p1],y[p1],x[p2],y[p1])&&Can_Farm(x[p2],y[p1],x[p2],y[p2]))return 1;
    return Can_Farm(x[p1],y[p1],x[p1],y[p2])&&Can_Farm(x[p1],y[p2],x[p2],y[p2]);
    //两种拐弯方式二选一，只要满足其一即可
}
int Road(int u,int v){return abs(x[u]-x[v])+abs(y[u]-y[v]);}//计算两点之间的曼哈顿距离
void Dijkstra(int St,int Ed){
    memset(dis,0x3f,sizeof(dis));
    memset(flag,0,sizeof(flag));//清空
    while(!q.empty())q.pop();dis[St]=0,q.push({St,0});//初始化
    while(!q.empty()){
        auto [u,d]=q.top();q.pop();//取队头
        if(flag[u])continue;flag[u]=1;//标记一下
        for(auto [v,w]:g[u]){//枚举边
            if(v<=n&&v!=Ed)continue;//除终点外不得走实点
            if(dis[v]>dis[u]+w){dis[v]=dis[u]+w;q.push({v,dis[v]});}//更新，进队
        }
    }
    return;//Dijkstra 结束
}
int main(){
    cin>>n;n2=n;
    for(int i=1;i<=n;i++){cin>>x[i]>>y[i];mp[{x[i],y[i]}]=i;}
    //最开始的读入 + 存储
    for(int i=1;i<=n;i++)
        for(int o=0;o<4;o++){//枚举
            int x2=x[i]+dx[o],y2=y[i]+dy[o];
            //计算出虚点的位置 (x2,y2)
            if(mp.count({x2,y2})==0)
                mp[{x2,y2}]=++n2,x[n2]=x2,y[n2]=y2;
            //如果还没有记录那么赶紧记录下来
            int id=mp[{x2,y2}];
            //取出对应 id，不论是之前记的还是刚收录的
            g[i].push_back({id,1}),g[id].push_back({i,1});
            //虚点和实点连双向边
        }
    for(int i=n+1;i<=n2;i++)
        for(int j=i+1;j<=n2;j++){//枚举要连边的虚点编号
            if(!Can_Merge(i,j))continue;//如果不应该被连边那么跳过
            int d=Road(i,j);//计算出其所对应的曼哈顿距离
            g[i].push_back({j,d}),g[j].push_back({i,d});
            //连双向边，边权为曼哈顿距离
        }
    for(int i=1;i<=n;i++){
        int Ed=(i==n?1:i+1);//对应计算出终点（注意最后要环回来）
        Dijkstra(i,Ed);//跑一遍 Dijkstra，从起点到终点
        if(dis[Ed]==0x3f3f3f3f){cout<<"-1\n";return 0;}//如果跑不过去那么直接无解
        ans+=dis[Ed];//否则把对应消耗加进去
    }
    cout<<ans<<"\n";//最后输出
    return 0;//结束！
}
